package ru.memearena.scout.application; import org.springframework.stereotype.Component; import ru.memearena.meme.domain.*; import ru.memearena.ranking.domain.WilsonScoreCalculator; import ru.memearena.scout.domain.*; import java.time.*; import java.util.*;
@Component public class ScoutPolicies{ private final ScoutProperties p; public ScoutPolicies(ScoutProperties p){this.p=p;} public boolean eligible(Meme m,UUID user,boolean already,Instant now){return m.getModerationStatus()==ModerationStatus.APPROVED&&m.getApprovedAt()!=null&&!already&&!m.getApprovedAt().plus(Duration.ofHours(p.earlyWindowHours)).isBefore(now)&&m.getBattlesCount()<p.maxEarlyBattles;} public int points(MemePrediction pr, Meme meme){int b=pr.getBattlesBeforeVote()<5?50:pr.getBattlesBeforeVote()<15?30:15; Duration d=Duration.between(meme.getApprovedAt(),pr.getPredictedAt()); if(!d.minus(Duration.ofMinutes(60)).isPositive()) b+=20; else if(!d.minus(Duration.ofHours(6)).isPositive()) b+=10; return b;} public boolean success(Meme target,List<Meme> cohort){List<Meme> eligible=cohort.stream().filter(m->m.getModerationStatus()==ModerationStatus.APPROVED&&m.getBattlesCount()>=p.minimumBattlesForResolution).toList(); if(eligible.size()<4){double wr=target.getBattlesCount()==0?0:(double)target.getWins()/target.getBattlesCount(); return target.getBattlesCount()>=p.minimumBattlesForResolution&&wr>=p.fallbackWinRate&&target.getRating()>=p.fallbackRating;} var sorted=new ArrayList<>(eligible); sorted.sort(Comparator.<Meme>comparingDouble(m->WilsonScoreCalculator.lowerBound(m.getWins(),m.getLosses())).reversed().thenComparing(Meme::getRating,Comparator.reverseOrder()).thenComparing(Meme::getBattlesCount,Comparator.reverseOrder()).thenComparing(Meme::getApprovedAt)); int n=Math.max(1,(int)Math.ceil(sorted.size()*p.successPercentile)); return sorted.subList(0,n).stream().anyMatch(m->m.getId().equals(target.getId()));} public boolean resolvable(Meme m,Instant now){return m.getApprovedAt()!=null&&!m.getApprovedAt().plus(Duration.ofHours(p.resolutionDelayHours)).isAfter(now)&&m.getBattlesCount()>=p.minimumBattlesForResolution;} public boolean expired(Meme m,Instant now){return m.getApprovedAt()!=null&&!m.getApprovedAt().plus(Duration.ofHours(p.expirationHours)).isAfter(now)&&m.getBattlesCount()<p.minimumBattlesForResolution;} }
